import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"49. Personal Carer S Leave","description":"","frontmatter":{"title":"49. Personal Carer S Leave","eba":"Medical Specialists 2022-2026","topics":["leave","personal-leave"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/49-personal-carer-s-leave.md","filePath":"ebas/medical-specialists/leave/49-personal-carer-s-leave.md"}'),s={name:"ebas/medical-specialists/leave/49-personal-carer-s-leave.md"};function n(i,e,l,c,p,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_49-personal-carer-s-leave" tabindex="-1">49. Personal Carer S Leave <a class="header-anchor" href="#_49-personal-carer-s-leave" aria-label="Permalink to &quot;49. Personal Carer S Leave&quot;">​</a></h1><p><strong>49.1</strong> Paid personal/carer’s leave</p><p><strong>(a)</strong> Paid personal/carer&#39;s Leave is available to a Doctor who is absent because of:</p><p><strong>(i)</strong> personal illness or injury;</p><p><strong>(ii)</strong> personal illness or injury of an immediate family or household member who requires the Doctor&#39;s care or support;</p><p><strong>(iii)</strong> an unexpected emergency affecting an immediate family or household member who requires the Doctor&#39;s care or support; or</p><p><strong>(iv)</strong> the requirement to provide ongoing care and attention to another person who is wholly or substantially dependent on the Doctor, provided that the care and attention is not wholly or substantially on a commercial basis.</p><p><strong>(b)</strong> A Full-time Doctor is entitled to 10 working days’ paid personal/carer&#39;s leave for each year of service (pro rata for Fractional Doctors).</p><p><strong>(c)</strong> In addition to, but separate from, personal/carer&#39;s leave under subclause 49.1(b), a Full-time Doctor is entitled to 18 working days&#39; additional paid sick leave due to personal illness or injury for each year of service (pro rata for Fractional Doctors).</p><p><strong>(d)</strong> A Doctor’s entitlement under this clause accrues progressively during a year of service according to the Doctor’s ordinary hours of work and unused personal/carer’s leave and additional paid sick leave accumulates from year to year.</p><p><strong>49.2</strong> Immediate family or household</p><p><strong>(a)</strong> The term immediate family means:</p><p><strong>(i)</strong> a spouse, de facto partner, child, parent, grandparent, grandchild or sibling of the Doctor; or</p><p><strong>(ii)</strong> a child, parent, grandparent, grandchild or sibling of a spouse or de facto partner of the Doctor.</p><p><strong>49.3</strong> Use of accumulated personal/carer’s leave</p><p><strong>(a)</strong> This entitlement is subject to the following:</p><p><strong>(i)</strong> Where practicable, the Doctor must notify the Health Service before the start of the first shift from which the Doctor will be absent. The Doctor must notify the Health Service of:</p><p>A. the reasons for the Doctor taking such leave; and</p><p>B. the estimated length of absence;</p><p><strong>(ii)</strong> And additionally, in the case of carer’s leave:</p><p>A. the name of the person requiring care; and</p><p>B. the relationship of the person requiring care to the Doctor.</p><p><strong>(b)</strong> When practical, the Doctor must give the Health Service prior notice of their intended absence due to carer’s leave. If not practical to provide prior notice, the Doctor should, where possible, give notice by telephone at the first opportunity on the day of the absence beginning. Notice should otherwise be given in accordance with section 107(2)(a) of the Act</p><p><strong>49.4</strong> Transfer of unused personal leave accruals</p><p>Where a Doctor transfers from one Health Service to another, accumulated personal/carer&#39;s leave and additional paid sick leave pursuant to subclause 49.1(c) (if any) to the Doctor’s credit up to a maximum of two hundred and eighty working days will be credited to the Doctor in his/her new employment. The onus of proving accumulated personal/carer&#39;s leave and additional paid sick leave pursuant to subclause 49.1(c) credit will rest with the Doctor, but a statement signed by an authorised Officer of the Doctor’s former Health Service certifying the amount of accumulated personal/carer&#39;s leave and additional paid sick leave pursuant to subclause 49.1(c) credit will constitute acceptable proof.</p><p><strong>49.5</strong> Absence on public holidays</p><p>If the period during which a Doctor takes paid personal/carer&#39;s leave or additional paid sick leave pursuant to subclause 49.1(c) includes a day or part-day that is a public holiday in the place where the Doctor is based for work purposes, the Doctor is taken</p><p>not to be on paid personal/carer&#39;s leave or additional paid sick leave pursuant to subclause 49.1(c) on that public holiday.</p><p><strong>49.6</strong> Unpaid personal leave</p><p>Where a Doctor has exhausted all paid personal/carer’s leave entitlements, he/she is entitled to take unpaid carer’s leave to provide care and support in the circumstances outlined in subclause 49.1(a) (and subject to subclauses 49.3(a) and 49.7) of this Agreement. The organisation and the Doctor will agree on the period. In the absence of agreement the Doctor is entitled to take up to two days&#39; unpaid carer’s leave per occasion.</p><p><strong>49.7</strong> Evidence requirements – Personal Leave</p><p>Upon request, a Doctor must provide the Health Service evidence that would satisfy a reasonable person that the leave taken is for a reason specified in this clause. The Doctor is not entitled to take leave under this clause unless the Doctor provides such evidence upon request.</p>',32)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
